import * as fs from 'fs';

function solve() {
    const input = fs.readFileSync('/dev/stdin', 'utf-8');
    const tokens = input.split(/\s+/);

    const iterator = {
        pos: 0,
        next() {
            return tokens[this.pos++];
        }
    };

    const N = parseInt(iterator.next());
    const Q = parseInt(iterator.next());

    const starts: number[] = new Array(N);
    const ends: number[] = new Array(N);

    for (let i = 0; i < N; i++) {
        starts[i] = parseInt(iterator.next());
        ends[i] = parseInt(iterator.next());
    }

    starts.sort((a, b) => a - b);
    ends.sort((a, b) => a - b);

    const results: string[] = [];

    for (let i = 0; i < Q; i++) {
        const query = parseInt(iterator.next());

        // Count starts <= query
        // upper_bound for query in starts
        let l = 0, r = N;
        while (l < r) {
            const mid = (l + r) >> 1;
            if (starts[mid] <= query) {
                l = mid + 1;
            } else {
                r = mid;
            }
        }
        const countStart = l;

        // Count ends < query
        // lower_bound for query in ends (first element >= query)
        l = 0; r = N;
        while (l < r) {
            const mid = (l + r) >> 1;
            if (ends[mid] < query) {
                l = mid + 1;
            } else {
                r = mid;
            }
        }
        const countEnd = l;

        results.push((countStart - countEnd).toString());
    }

    console.log(results.join(' '));
}

solve();
```

